INSERT INTO `reviews` VALUES (1,2,1,NULL,5,'Mona Lisa reprodüksiyonunu sipariş ettim, gelemez diye düşünürdüm ama fotoğraflar gerçekten çarpıcı. Siparişimi sabırsızlıkla bekliyorum.',0,'2026-05-09 19:27:38'),(2,3,1,NULL,4,'Sergide yakından gördüm; gizemli gülüşü gerçekten büyüleyici. Her açıdan farklı bir ifade taşıyor.',0,'2026-05-09 19:27:38'),(3,2,2,NULL,5,'Yıldızlı Gece hayallerimde gezdiğim bir tablo; her izlediğimde sarmal bulutların içinde kayboluyorum.',0,'2026-05-09 19:27:38'),(4,3,9,NULL,5,'Kaplumbağa Terbiyecisi Osmanlı sanatının zirvesi; bu eserin milli koleksiyonumuzdaki yerini her gördüğümde gurur duyuyorum.',0,'2026-05-09 19:27:38'),(5,7,1,NULL,4,'Leonardo\'nun bu efsane portresini online görmek ayrı bir heyecan. Sanat tarihinin en ikonik yüzü diyebilirim.',0,'2026-05-10 18:46:19'),(6,7,9,NULL,5,'Osman Hamdi Bey\'in bu eseri Türk sanat tarihinin en güçlü simgelerinden biri. Görebilmek harikaydı.',0,'2026-05-10 18:50:11'),(7,9,27,NULL,5,'Ayçiçekleri baskısı bugün elime geçti; sarının bu kadar sıcak ve canlı olabileceğini görmek inanılmaz. Çerçeveleyip salona astım.',1,'2026-05-11 12:00:00'),(8,10,30,NULL,5,'Vitruvius Adamı reprodüksiyonu kargo kutusundan çıktığında büyülendim. İnce mürekkep çizgileri baskıda da eksiksiz korunmuş.',1,'2026-05-11 12:05:00'),(9,11,19,NULL,5,'İzlenim: Gün Doğumu evime ulaştı; liman sisinin o yumuşak ışıkta nasıl eridiğini baskıda da hissedebiliyorsunuz. Harika bir seçim oldu.',1,'2026-05-11 12:10:00'),(10,12,31,NULL,4,'Hayatın Dansı\'nı sipariş ettim, onay bekliyorum. Munch\'ün aşk-gençlik-ölüm döngüsünü bu kadar etkileyici anlatan başka eser gördüğümü sanmıyorum.',0,'2026-05-11 12:15:00'),(11,13,20,NULL,5,'Nilüferler baskısı çok güzel paketlenmiş olarak geldi. Monet\'nin su zambaklarındaki huzuru oturma odama da taşıdı, çok memnunum.',1,'2026-05-11 12:25:00'),(12,14,32,NULL,5,'Klimt\'in Adele\'si eve geldiğinde altın yaprakların parıltısını baskıda görmek gerçekten şaşırttı. Çalışma odama astım, odayı aydınlattı.',1,'2026-05-11 12:35:00'),(13,15,16,NULL,5,'Kuzey\'in Mona Lisası kapıma ulaştı; o bakışın ve ışık oyununun baskıda bu denli güçlü aktarılabileceğini düşünmezdim.',1,'2026-05-11 12:40:00'),(14,16,26,NULL,5,'Dalí\'nin Uyku\'sunu sipariş ettim; beklentim çok yüksek. Bilinçaltının bu kadar rafine görselleştirildiği başka eser düşünemiyorum.',0,'2026-05-11 12:50:00'),(15,22,2,NULL,5,'Yıldızlı Gece reprodüksiyonu kargoda hasar görmeden geldi. Fırça dokuları baskıda neredeyse elle hissedilebilecek kadar belirgin.',1,'2026-05-11 12:20:00'),(16,13,29,NULL,4,'İlkbahar\'ı sipariş ettim ve kargoda görünüyor; bu hafta teslim bekliyorum. Botticelli\'nin bu bahar masalını çok seviyorum.',0,'2026-05-11 13:00:00'),(17,14,17,NULL,4,'Süt Döken Kadın kargoda, merakla bekliyorum. Vermeer\'in Barok ışık kullanımı beni her seferinde hayrete düşürüyor.',0,'2026-05-11 13:05:00'),(18,17,8,NULL,5,'Venüsün Doğuşu baskısı evime geldi; Botticelli\'nin zarif renk geçişleri baskıda da çarpıcı. Yatak odamın baş duvarına layıkıyla yerleşti.',1,'2026-05-11 13:40:00'),(19,18,6,NULL,5,'Belleğin Azmi kargodan sağlam çıktı; eriyen saatler baskıda da o tuhaf ve büyüleyici atmosferi tam anlamıyla korumuş.',1,'2026-05-11 13:25:00'),(20,19,4,NULL,5,'Atina Okulu baskısını aldığımda detay zenginliği karşısında donup kaldım. Felsefenin ve sanatın bu denli buluştuğu başka eser yok.',1,'2026-05-11 12:55:00'),(21,20,5,NULL,5,'Sistine Şapeli\'nin bu ikonik sahnesinin baskısı eve ulaştı; Tanrı ile Adem\'in parmak uçlarının buluşması baskıda da tüyleri diken diken ediyor.',1,'2026-05-11 13:10:00'),(22,21,10,NULL,5,'Son Akşam Yemeği baskısı düşündüğümden çok daha büyük ve etkileyici geldi. Karşısında oturup saatlerce inceleyebilirsiniz.',1,'2026-05-11 14:15:00'),(23,23,9,NULL,5,'Kaplumbağa Terbiyecisi evime ulaştı; Osman Hamdi Bey\'in o sakin ve gizemli atmosferi baskıda da kendini hissettiriyor. Harika bir eser.',1,'2026-05-11 13:55:00'),(24,9,11,NULL,4,'Galeri No. 13\'ü sipariş ettim; kargoda görünüyor. Çağdaş Türk soyut sanatından renk ve form dengesini bu kadar başarılı kullanan az eser var.',0,'2026-05-11 13:30:00'),(25,10,25,NULL,4,'Dikenli Kolye ile Otoportre kargoda; bekliyorum. Frida\'nın bu eserdeki kimlik sorgulaması ve direnci her bakışta farklı konuşuyor.',0,'2026-05-11 13:35:00'),(26,11,22,NULL,4,'Avignonlu Kızlar siparişini verdim, kargoda. Modern sanatın doğuşunu müjdeleyen bu eser evimde nasıl duracak merak ediyorum.',0,'2026-05-11 15:20:00'),(27,15,28,NULL,4,'Gece Kafesi kargoda yolda; Van Gogh\'un sarı sıcak ışıkla gecenin laciverdini bu denli zıtlaştırması eşsiz. Sabırsızlıkla bekliyorum.',0,'2026-05-11 15:40:00'),(28,17,14,NULL,4,'Zeybekler Kurtuluş Savaşı\'nda\'yı sipariş ettim; kargoda. Milli Mücadele\'nin direniş ruhunu bu denli epik anlatan başka tablo zor bulunur.',0,'2026-05-11 14:05:00'),(29,21,13,NULL,5,'Atatürk Portresi\'ni sipariş ettim ve kargoda görünüyor; cumhuriyetin kurucu liderini bu denli güçlü aktaran bir portreye sahip olmak büyük bir onur.',0,'2026-05-11 14:00:00'),(30,23,30,NULL,4,'Vitruvius Adamı kargoda; insan vücudunun altın oranını bu şekilde sanata dönüştüren Leonardo\'nun dehasına her seferinde hayran kalıyorum.',0,'2026-05-11 14:45:00'),(31,12,24,NULL,5,'İki Frida\'yı sipariş ettim, onaylanmasını bekliyorum. Sanatçının kimlik ikiliğini bu kadar güçlü tuvale yansıtması çok etkileyici.',0,'2026-05-11 15:00:00'),(32,22,12,NULL,3,'Karanlığın Çağrısı\'nı sipariş ettim; bekliyorum. Dijital sanat piyasasının büyümesini takip ediyorum ve bu eser ilgimi çekti.',0,'2026-05-11 15:45:00'),(33,19,12,NULL,3,'Karanlığın Çağrısı kargoda; merak ediyorum nasıl gelecek. Sanatçının acemilik dönemi eseri olduğunu bilerek sipariş ettim.',0,'2026-05-11 16:05:00'),(34,18,15,NULL,4,'Celile Hanım Portresi\'ni sipariş ettim; Osman Hamdi Bey\'in kadın figürlerine yaklaşımı her zaman zarafet ve derinlik içeriyor.',0,'2026-05-11 13:50:00'),(35,16,18,NULL,4,'Gece Devriyesi\'ni sipariş etmiştim ama iptal ettim çünkü boyutları evime uymadı. Eserin kendisi harika, Rembrandt\'ın ışık ustalığı eşsiz.',0,'2026-05-11 15:55:00'),(36,22,23,NULL,4,'Ağlayan Kadın siparişimi iptal ettim; farklı bir eser seçmeye karar verdim. Dora Maar\'ın kübist yorumu yine de çok güçlü bir eser.',0,'2026-05-11 14:55:00'),(37,9,3,NULL,4,'Çığlık siparişim onay bekliyor. Varoluşsal kaygıyı bu denli güçlü yansıtan ekspresyonist bir eser; çalışma odama çok yakışacak.',0,'2026-05-11 12:30:00'),(38,2,NULL,1,4,'Yağlıboya atölyesine kaydoldum, çok heyecanlıyım. Sıfırdan başlamak için mükemmel bir başlangıç gibi görünüyor.',0,'2026-05-09 19:27:38'),(39,9,NULL,1,5,'Yağlıboya Başlangıç Atölyesi hayatımda katıldığım en verimli 3 saatti. Eğitmen sabırla her fırça darbemizi tek tek düzeltti, çok şey öğrendim.',1,'2026-05-11 16:30:00'),(40,10,NULL,1,4,'Atölyeye katılmadan önce hiç fırça tutmamıştım; eğitmen o kadar anlaşılır anlattı ki ilk tuvalimden memnun ayrıldım.',1,'2026-05-11 16:35:00'),(41,11,NULL,1,5,'Sıfırdan başlayan biri olarak çok şey öğrendim. Malzemelerin dahil olması da organizasyonu çok kolaylaştırdı.',1,'2026-05-11 16:40:00'),(42,12,NULL,2,5,'Karakalem portre tekniklerini bu atölyede öğrenmek inanılmaz değerliydi. Eğitmen her katılımcıya ayrı ayrı ilgilendi.',1,'2026-05-11 16:50:00'),(43,13,NULL,2,4,'Orta seviye için çok uygun bir içerik; temel teknikleri atlayıp doğrudan pratik uygulamaya geçmek güzeldi.',1,'2026-05-11 16:55:00'),(44,14,NULL,2,5,'Portre çizimine merak sarmıştım ama bu atölye o merakı tutkuya dönüştürdü. Kesinlikle devam kurslarına da katılacağım.',1,'2026-05-11 17:00:00'),(45,15,NULL,3,5,'Doğadan ilham alarak suluboya öğrenmek bambaşka bir his. Açık havada çalışmak konsantrasyonu artırıyor ve eğitmen bunu çok iyi değerlendiriyor.',1,'2026-05-11 17:05:00'),(46,16,NULL,3,4,'Suluboya tekniklerini çok net anlattılar, evde de rahatlıkla uyguluyorum. Bir veya iki teknik daha eklenseydi mükemmel olurdu.',1,'2026-05-11 17:10:00'),(47,17,NULL,3,4,'Başlangıç seviyesi için son derece uygun tempo ve içerik; güven veren bir atölye ortamı vardı.',1,'2026-05-11 17:15:00'),(48,18,NULL,4,5,'Kil ile çalışmanın bu kadar keyifli olabileceğini hiç düşünmemiştim. Ellerimle bir şekil vermenin o tatmini kelimelerle anlatamam.',1,'2026-05-11 17:20:00'),(49,19,NULL,4,4,'Form ve doku çalışmaları çok öğreticiydi; seramiğin teknik boyutunu ilk defa bu kadar anlamlı kavradım.',1,'2026-05-11 17:25:00'),(50,20,NULL,4,5,'Her seviyeden katılımcı için gerçekten uygun bir program hazırlamışlar; yeni başlayanlar da deneyimliler de verimli ayrıldı.',1,'2026-05-11 17:30:00'),(51,21,NULL,5,5,'Procreate ile bu kadar çok şey yapılabileceğini bilmiyordum. Eğitmen katman yönetiminden renk teorisine kadar her şeyi çok anlaşılır aktardı.',1,'2026-05-11 17:35:00'),(52,22,NULL,5,4,'Dijital sanata geçmek isteyenler için mükemmel bir başlangıç noktası. Tablet ile vektör çizime bu kadar hızlı adapte olacağımı düşünmezdim.',1,'2026-05-11 17:40:00'),(53,23,NULL,5,5,'Eğitmen konusuna gerçekten hakim; her soruyu somut bir pratik örneğiyle yanıtladı. Çok değerliydi.',1,'2026-05-11 17:45:00'),(54,3,NULL,6,5,'Türk Resim Sanatı Sergisi\'ne rezervasyon yaptırdım; Osmanlıdan Cumhuriyete sanatımızın yolculuğunu görmek büyük heyecan verici.',0,'2026-05-09 19:27:38'),(55,9,NULL,6,5,'Osmanlıdan Cumhuriyete geçişi bu kadar tutarlı ve etkileyici anlatan bir sergi daha görmedim. Her eser ayrı bir dönem belgeği gibiydi.',1,'2026-05-11 17:50:00'),(56,11,NULL,6,5,'Her eser ayrı bir hikaye anlatıyordu; sergiyi gezerken Türk sanatının nasıl evrildiğini somut olarak hissettim.',1,'2026-05-11 17:55:00'),(57,13,NULL,6,4,'Sergi çok kapsamlı ve kaliteli kurgulanmış; tek eksiklik rehberli tur seçeneğinin olmaması, eklenseydi mükemmel olurdu.',1,'2026-05-11 18:00:00'),(58,15,NULL,6,5,'Türk sanatının bu kadar geniş bir yelpazede sergilenmesi nadiren rastladığım bir deneyimdi. Tüm arkadaşlarıma tavsiye ettim.',1,'2026-05-11 18:05:00'),(59,17,NULL,6,4,'Sergi alanı biraz kalabalık oldu ama eserlerin kalitesi ve düzeni bunu telafi etti. Yine de daha ferah bir ortam tercih ederdim.',1,'2026-05-11 18:10:00'),(60,10,NULL,7,5,'Rönesansı bu denli canlı hissettiren bir sergi Türkiye\'de ilk kez gördüm. Sanat tarihi seminerleri sergiyi anlam bakımından çok zenginleştirdi.',1,'2026-05-11 18:15:00'),(61,12,NULL,7,4,'Sanat tarihi seminerleri sergiye inanılmaz değer kattı; reprodüksiyonlar gerçeği aratmıyor desek yeri var.',1,'2026-05-11 18:20:00'),(62,14,NULL,7,5,'Rönesans ustalarının eserlerini bu kadar yakından incelemek sanat tarihine bakışımı tamamen değiştirdi.',1,'2026-05-11 18:25:00'),(63,16,NULL,7,4,'Sergi çok iyi organize edilmişti; akış mantıklıydı ve açıklama kartları yeterliydi. Tekrar gelmek isterim.',1,'2026-05-11 18:30:00'),(64,18,NULL,8,5,'Genç Türk sanatçıların bu denli özgün işler üretmesi çok sevindirici; sergi yerli sanata desteğin ne kadar önemli olduğunu bir kez daha gösterdi.',1,'2026-05-11 18:35:00'),(65,20,NULL,8,4,'Karma sergi çok iyi düzenlenmiş; farklı tarzlardaki eserlerin aynı alanda bu kadar uyumlu sergilenmesi dikkat çekiciydi.',1,'2026-05-11 18:40:00'),(66,22,NULL,8,4,'Yerli sanatçılara bu platformun sağlanması çok değerli; bazı isimler gerçekten büyük bir potansiyel taşıyor.',1,'2026-05-11 18:45:00'),(67,19,NULL,9,5,'Duygunun bu kadar güçlü ifade edildiği bir sergi daha görmemiştim; her oda farklı bir hissiyat yaratıyordu.',1,'2026-05-11 18:50:00'),(68,21,NULL,9,4,'Van Gogh ve Munch\'ün bir arada sergilenmesi inanılmaz bir atmosfer yarattı; tematik kurgu çok başarılıydı.',1,'2026-05-11 18:55:00'),(69,23,NULL,9,5,'Her oda farklı bir duygusal katmana karşılık geliyordu; bu tematik yaklaşım sergiyi sıradan bir gezinin çok ötesine taşıdı.',1,'2026-05-11 19:00:00'),(70,9,NULL,10,5,'NFT ve dijital sanat paneli gerçekten aydınlatıcıydı; blockchain ile sanat piyasasının kesişimini bu kadar somut açıklayan bir etkinliğe ilk kez katıldım.',1,'2026-05-11 19:05:00'),(71,12,NULL,10,4,'Konuşmacılar sektörün içinden isimlerdi ve güncel örnekler sundular; soru-cevap kısmı biraz daha uzun olabilirdi.',1,'2026-05-11 19:10:00'),(72,15,NU